import { createAdminClient } from '@/lib/supabase/admin';
import { notFound } from 'next/navigation';
import { Metadata } from 'next';
import { Bookmark } from '@/lib/types';

export async function generateMetadata({ params }: { params: Promise<{ handle: string }> }): Promise<Metadata> {
  const { handle } = await params;
  return {
    title: `@${handle} — Bookmarks`,
  };
}

export default async function PublicProfilePage({ params }: { params: Promise<{ handle: string }> }) {
  const { handle: rawHandle } = await params;

  // Strip any leading '@' from the handle, lowercase it
  const handle = rawHandle.replace(/^@/, '').toLowerCase();

  const supabase = createAdminClient();

  // Query the profiles table for that handle
  const { data: profile } = await supabase
    .from('profiles')
    .select('*')
    .eq('handle', handle)
    .single();

  if (!profile) {
    notFound();
  }

  // Query bookmarks where user_id = profile.id AND is_public = true, ordered by created_at descending
  const { data: bookmarks } = await supabase
    .from('bookmarks')
    .select('*')
    .eq('user_id', profile.id)
    .eq('is_public', true)
    .order('created_at', { ascending: false });

  return (
    <div className="max-w-2xl mx-auto py-12 px-4">
      <h1 className="text-4xl font-extrabold mb-2 tracking-tight">@{handle}</h1>
      <p className="text-gray-500 mb-10 text-lg">
        {bookmarks?.length || 0} public bookmark(s)
      </p>

      {!bookmarks || bookmarks.length === 0 ? (
        <div className="text-center py-20 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200">
          <p className="text-gray-400 text-lg">No public bookmarks yet.</p>
        </div>
      ) : (
        <div className="flex flex-col gap-4">
          {bookmarks.map((bookmark: Bookmark) => (
            <a
              key={bookmark.id}
              href={bookmark.url}
              target="_blank"
              rel="noopener noreferrer"
              className="group block w-full p-6 bg-white rounded-xl border border-gray-100 hover:border-violet-500 transition-all shadow-sm hover:shadow-md"
            >
              <h2 className="font-bold text-xl text-gray-900 group-hover:text-violet-600 transition-colors mb-1">
                {bookmark.title}
              </h2>
              <p className="text-gray-400 text-sm truncate font-medium">
                {bookmark.url}
              </p>
            </a>
          ))}
        </div>
      )}
    </div>
  );
}

